INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES
(30000,1,'智慧交通与车联网介绍','智慧交通结合多种技术解决城市拥堵痛点 车联网可以利用 GPS 技术、惯导技术、车载摄像头、雷达及激光雷达实现高可靠高精度的定位服务和全工况、无盲区的感知外部信息，并可以利用实时的交管信息基于 AI 技术和数字化的道路基础设施实现城市智能交通控制技术、交通分析研判技术和车路协同技术在治堵等多交通领域的应用。交通控制技术主要是利用交通控制设施对交通流进行组织优化，并通过调节、诱导、分流来保障交通安全顺畅进行。其中，比较典型的是使用 AI 技术来控制交通信号灯，如根据交通流量控制信号灯时长来保证交通流...','**智慧交通结合多种技术解决城市拥堵痛点**\n\n**车联网**可以利用 GPS 技术、惯导技术、车载摄像头、雷达及激光雷达实现高可靠高精度的定位服务和全工况、无盲区的感知外部信息，并可以利用实时的交管信息基于 AI 技术和数字化的道路基础设施实现城市智能交通控制技术、交通分析研判技术和车路协同技术在治堵等多交通领域的应用。交通控制技术主要是利用交通控制设施对交通流进行组织优化，并通过调节、诱导、分流来保障交通安全顺畅进行。其中，比较典型的是使用 AI 技术来控制交通信号灯，如根据交通流量控制信号灯时长来保证交通流畅。近年来，随着大量非结构化数据的充分利用，交通分析研判技术已经能实现跨区域、跨部门、跨行业的信息共享和深度挖掘。基于各类交通数据，同时融合车辆和道路信息，交通分析研判技术能为交通相关部门以及相关企业如物流公司等，提供辅助决策支持，具有精准、科学、高效的特点。车路协同技术也采用先进的无线通信和互联网技术，全方位实施车车、车路动态实时信息交互，在全时空动态交通信息采集与融合的基础上开展车辆主动安全控制和道路协同管理，充分实现人车路的有效协同，从而保障在复杂交通环境下提高路网运行效率。\n\n国内政策频出势头强劲，智能汽车互联先导区示范区并行。近几年，我国致力于打造制造强国、科技强国、网络强国、科技强国、数字中国、智慧社会。车联网作为一个在萌芽期的创新产业，对我国科技发展具有重要战略意义。因此，我国正在抓住产业智能化发展机遇，加快推进智能汽车创新发展。当前，国家各个部门政策频出，为构建协同开放的智能汽车技术创新体系、构建跨界融合的智能汽车产业生态体系、构建先进完备的智能汽车基础设施体系、构建系统完善的智能汽车法规标准体系、构建科学规范的智能汽车产品监管体系做好准备。我国将以统筹谋划、协同推进；创新驱动、平台支撑；市场主导、跨界融合；开放合作、安全可控为发展车联网基本原则，到 2025 可规模化生产有条件驾驶的智能汽车，实现高度自动驾驶的智能汽车在特定环境下市场化应用。2035 到 2050 年我国将打造成为安全、高效、绿色、文明的智能汽车强国，智能汽车也会充分保障人们的日常所需。\n\n智慧交运领域的细分类别主要包括智慧高速、ETC 与交通运输。在智慧高速方面，公司提供高速公路机电系统及智慧隧道整体解决方案，包括高速公路监控、收费、通信、隧道机电等高速公路基础设施，并致力于提高高速公路机电系统基础设施数字化规模，构建智能高效的高速公路机电系统，为公众提供安全高效的出行服务，为管理者提供精细化智能化管理。\n\n智慧路网业务监督路网安全情况。公司采用物联网、云计算、大数据分析等技术，为公路、高速公路等管理部门提供全天候监测、公路突发事件快速协调处置、收费稽查和收费综合分析与辅助决策服务，包括路网智能化感知、路警联勤联动应急指挥调度、收费清分稽核、桥隧等重点区域动态监测及综合管养、路产全生命周期管理、全业务移动协同 APP 等，并为出行者提供准确高效、伴随式的出行服务。\n\n智慧交管业务综合整治城市交通问题。公司深入解析城市交通发展难题，剖析拥堵成因、运行态势、综合需求，通过科学有效的方法，从交通工程、交通组织、交通控制、慢性交通、公共交通等方面出发，开展综合交通治理工作，缓解和治理城市交通发展难题；依托大数据、人工智能、云计算等前沿科技，全面搭建基于交通管理业务的系统平台，赋能智慧城市建设。\n\n**车联网主要有有 DSRC 和 C-V2X 两类技术**\n\nDSRC 为专用短程通信，是以 IEEE802.11p 协定为基础的主要用于单向或双向短程到中程的无线通信技术。DSRC 在实现 V2V 时，可使车辆之间相互直接通信，而不涉及蜂窝技术或其他基础设施。每辆车以安全匿名的方式每秒发送 10 次其位置、航向和速度等等。一定范围内的所有车辆都将接收到该信息，并且每台接车会根据该信息自动评估发送车所带来的风险。DSRC 在实现 V2I 时，使车载设备(OBU)与路侧基础设施(RSU) 进行通信，路侧设施可以获取附近区域车辆的信息并发布各种实时信息。DSRC 是以网络安全最大化为准则设计的，接收信号的车辆会验证接收到消息的真实性，但不会暴露车辆的身份，因此不会侵犯司机的隐私。\n\n**DRSC 实现 V2I 与 V2V 通信**\n\nC-V2X 即蜂窝车用无线通信技术。目前市场正在向 4GC-V2X 升级，5GC-V2X 正在标准化过程中，未来会随着汽车智能互联的落地同步到来。C-V2X 得到了许多移动运营商、主要移动设备制造商和汽车制造商的支持，包括奥迪(Audi)、宝马(BMW)、戴姆勒 (Daimler)、福特(Ford)、PSA、上汽(SAIC)、特斯拉(Tesla)和丰田(Toyota)。移动运营商、设备供应商和汽车制造商正联手对 C-V2X 进行测试。中国将成为首批部署 CV2X 的国家之一，而一些欧洲国家也可能成为采用 C-V2X 的先锋。\n\n**V2X 终端设备市场竞争**\n\n由于目前车路协同市场的商业模式（怎么赢利）、由谁出资建设（政府、运营商、高速公路公等）尚不清晰，所以还无法深入探讨未来的竞争格局。现在可探讨的是市场空间和各厂商方案差异的问题。车路协同主要靠在车端和路端分别加装 RSU（智能感知基站）、 OBU（车侧智能处理单元）、以及对 ITS 系统进行改造（软件业务，改造信号机+云控平台建设）三部分工作来实现的。\n\n车联网目前处在萌芽期，行业增长潜力巨大。在 5G 以及人工智能等新一代信息技术的发展浪潮处于高速发展的浪潮中，在汽车行业从传统机械设备朝着智能化、网联化方向发展过程中，车联网行业作为新一代信息技术与汽车行业的新结合体，正迎来明朗的发展机遇。\n\n以下是基于阿里飞天平台，智慧交通框架\n\n参考：\n\n附件：1.[国家车联网产业标准体系建设指南（总体要求）](http://www.miit.gov.cn/n1146285/n1146352/n3054355/n3057497/n3057502/c5814264/part/5814268.docx)\n\n2.[国家车联网产业标准体系建设指南（信息通信）](http://www.miit.gov.cn/n1146285/n1146352/n3054355/n3057497/n3057502/c5814264/part/5814269.docx)\n\n3.[国家车联网产业标准体系建设指南（电子产品和服务）](http://www.miit.gov.cn/n1146285/n1146352/n3054355/n3057497/n3057502/c5814264/part/5814270.docx)\n\n---\n今天先到这儿，希望对云原生，技术领导力， 企业管理，系统架构设计与评估，团队管理, 项目管理, 产品管管，团队建设 有参考作用 , 您可能感兴趣的文章:\n\n如有想了解更多软件设计与架构, 系统IT,企业信息化, 团队管理 资讯，请关注我的微信订阅号：\n\n[![MegadotnetMicroMsg_thumb1_thumb1_thu[2]](/api/uploads/files/cnblogs/211054062506158-b8ed0bc1ce.jpg)](http://images.cnitblog.com/blog/15172/201503/211054051419485.jpg)\n\n作者：\n出处：\n本文版权归作者和博客园共有，欢迎转载，但未经作者同意必须保留此段声明，且在文章页面明显位置给出原文连接，否则保留追究法律责任的权利。\n该文章也同时发布在我的独立博客中-Petter Liu Blog。\n\n---\n\n原文链接：https://www.cnblogs.com/wintersun/p/15968878.html','https://images.unsplash.com/photo-1486312338219-ce68d2c6f44d?w=800','企业信息化其他',NULL,0,NULL,'cnblogs-wintersun-p-15968878','智慧交通与车联网介绍 - 博客园','智慧交通结合多种技术解决城市拥堵痛点 车联网可以利用 GPS 技术、惯导技术、车载摄像头、雷达及激光雷达实现高可靠高精度的定位服务和全工况、无盲区的感知外部信息，并可以利用实时的交管信息基于 AI 技术和数字化的道路基础设施实现城市智能交通...',0,'PUBLISHED',5693,104,345,0,'2022-03-05 18:02','2022-03-05 18:02','2026-05-10 17:35:33',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title