(30004,1,'多语言DB数据库表设计','国际化产品大致可分为两种：一是根据不同国家/地区分别设计不同的信息架构和用户界面；二是出于成本考虑用相同的架构和设计做不同语言的适配。此处是第二类： // Retrieve titles for all languages sql = "SELECT p., pt.title, pt.description, l.name as languagename FROM appproduct p','## 多语言DB数据库表设计\n\n国际化产品大致可分为两种：一是根据不同国家/地区分别设计不同的信息架构和用户界面；二是出于成本考虑用相同的架构和设计做不同语言的适配。此处是第二类：\n\n### 示例一：\n\n![图片](/api/uploads/files/cnblogs/additional_translation_approach_tbl-23adf95729.png)\n\n#### 脚本如下：\n\n> CREATE TABLE IF NOT EXISTS `app_product` (\n> `id` int(11) NOT NULL AUTO_INCREMENT,\n> `date_created` datetime NOT NULL,\n> `price` decimal(10,2) NOT NULL DEFAULT \'0.00\',\n> PRIMARY KEY (`id`)\n> ) ENGINE=InnoDB DEFAULT CHARSET=latin1;\n> CREATE TABLE IF NOT EXISTS `app_product_translation` (\n> `id` int(11) NOT NULL AUTO_INCREMENT,\n> `product_id` int(11) NOT NULL DEFAULT \'0\',\n> `language_code` char(2) NOT NULL,\n> `title` text CHARACTER SET utf8 COLLATE utf8_unicode_ci NOT NULL,\n> `description` text CHARACTER SET utf8 COLLATE utf8_unicode_ci NOT NULL,\n> PRIMARY KEY (`id`),\n> KEY `translation_id` (`product_id`),\n> KEY `language_code` (`language_code`)\n> ) ENGINE=InnoDB DEFAULT CHARSET=latin1;\n> CREATE TABLE IF NOT EXISTS `app_language` (\n> `code` char(2) NOT NULL,\n> `name` varchar(20) NOT NULL,\n> PRIMARY KEY (`code`)\n> ) ENGINE=InnoDB DEFAULT CHARSET=latin1;\n\n#### 查询示例\n\n// Retrieve titles for all languages\nsql = "SELECT p.*, pt.title, pt.description, l.name as language_name\nFROM `app_product` p\nINNER JOIN `app_product_translation` pt ON p.id = pt.product_id\nINNER JOIN `app_language` l ON pt.language_code = l.code\nWHERE p.id = 1";\n\n// Retrieve appropriate title according to the chosen language in the system\nsql = "SELECT p.*, pt.title, pt.description\nFROM `app_product` p\nINNER JOIN `app_product_translation` pt ON p.id = pt.product_id\nWHERE p.id = 1 AND pt.language_code = \'".$_SESSION[\'current_language\']."\'";\n\n### 示例二：\n\n#### 查询示例\n\n```\nSELECT pt.product_name, pt.description, p.price\nFROM order_line o, product p, product_translation pt, language l\n\tWHERE o.product_id = p.id AND \n\tAND p.id = pt.product_non_trans_id\n\tAND pt.language_id = l.id\n               AND l.name = @in_language\n\tAND id = ;\n```\n\n```\n```\n\n```\n```\n\n---\n今天先到这儿，希望对云原生，技术领导力， 企业管理，系统架构设计与评估，团队管理, 项目管理, 产品管管，团队建设 有参考作用 , 您可能感兴趣的文章:\n\n如有想了解更多软件设计与架构, 系统IT,企业信息化, 团队管理 资讯，请关注我的微信订阅号：\n\n[![MegadotnetMicroMsg_thumb1_thumb1_thu[2]](/api/uploads/files/cnblogs/211054062506158-b8ed0bc1ce.jpg)](http://images.cnitblog.com/blog/15172/201503/211054051419485.jpg)\n\n作者：\n出处：\n本文版权归作者和博客园共有，欢迎转载，但未经作者同意必须保留此段声明，且在文章页面明显位置给出原文连接，否则保留追究法律责任的权利。\n该文章也同时发布在我的独立博客中-Petter Liu Blog。\n\n---\n\n原文链接：https://www.cnblogs.com/wintersun/p/15314273.html','https://images.unsplash.com/photo-1486312338219-ce68d2c6f44d?w=800','企业信息化其他',NULL,0,NULL,'cnblogs-wintersun-p-15314273','多语言DB数据库表设计 - 博客园','国际化产品大致可分为两种：一是根据不同国家/地区分别设计不同的信息架构和用户界面；二是出于成本考虑用相同的架构和设计做不同语言的适配。此处是第二类： // Retrieve titles for all languages sql = "S...',0,'PUBLISHED',5750,57,296,0,'2021-09-20 14:40','2021-09-20 14:40','2026-05-10 17:35:33',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`view_count`=VALUES(`view_count`),`like_count`=VALUES(`like_count`),`favorite_count`=VALUES(`favorite_count`),`comment_count`=VALUES(`comment_count`),`published_at`=VALUES(`published_at`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
