SET NAMES utf8mb4;
USE `my_blog`;
START TRANSACTION;














UPDATE `blog_article_tag` SET `deleted_at`='2026-05-10 17:35:33',`updated_at`='2026-05-10 17:35:33' WHERE `article_id` IN (30000, 30001, 30002, 30003, 30004, 30005, 30006, 30007, 30008);


UPDATE `blog_column_article` SET `deleted_at`='2026-05-10 17:35:33',`updated_at`='2026-05-10 17:35:33' WHERE `column_id`=9400003;


UPDATE `blog_topic_article` SET `deleted_at`='2026-05-10 17:35:33',`updated_at`='2026-05-10 17:35:33' WHERE `topic_id` IN (9503001);


UPDATE `blog_tag` t SET `use_count` = (SELECT COUNT(*) FROM `blog_article_tag` atg WHERE atg.`tag_name` = t.`name` AND atg.`deleted_at` IS NULL) WHERE t.`name` IN ('企业信息化其他', '前端', '数据库', '程序员');

UPDATE `blog_column` c SET `article_count` = (SELECT COUNT(*) FROM `blog_column_article` ca INNER JOIN `blog_article` a ON a.`id` = ca.`article_id` WHERE ca.`column_id` = c.`id` AND ca.`deleted_at` IS NULL AND a.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED') WHERE c.`id` IN (9400003);

UPDATE `blog_topic` t SET `article_count` = (SELECT COUNT(*) FROM `blog_topic_article` ta INNER JOIN `blog_article` a ON a.`id` = ta.`article_id` WHERE ta.`topic_id` = t.`id` AND ta.`deleted_at` IS NULL AND a.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED') WHERE t.`id` IN (9503001);

COMMIT;
